import { NextRequest, NextResponse } from "next/server"
import {connectDB} from "@/lib/db"
import Cost from "@/models/ExecutionCost"
import mongoose from "mongoose"

export async function POST(req: NextRequest) {
  try {
    await connectDB()

    const body = await req.json()

    const { executionWorkspaceId, category, plannedAmount, actualAmount } = body

    // Validation
    if (!executionWorkspaceId || !category) {
      return NextResponse.json(
        { message: "Missing required fields: executionWorkspaceId, category" },
        { status: 400 }
      )
    }

    // ============================================================
    // ENSURE COLLECTION EXISTS - Run on first creation
    // ============================================================
    try {
      const collections = await mongoose.connection.db?.listCollections().toArray()
      const collectionNames = collections?.map((c) => c.name) || []

      // If costs collection doesn't exist, create it
      if (!collectionNames.includes("costs")) {
        console.log("Creating 'costs' collection...")
        await mongoose.connection.db?.createCollection("costs")
        console.log("✅ 'costs' collection created successfully")
      }

      // Create indexes for performance
      await Cost.collection.createIndex({ executionWorkspaceId: 1 })
      await Cost.collection.createIndex({ createdAt: -1 })
      await Cost.collection.createIndex({ executionWorkspaceId: 1, category: 1 })
      await Cost.collection.createIndex({ approvalStatus: 1 })
    } catch (collectionError) {
      console.error("Error with collection creation:", collectionError)
      // Continue anyway - collection might already exist
    }

    // ============================================================
    // CREATE THE COST DOCUMENT
    // ============================================================
    const newCost = await Cost.create({
      executionWorkspaceId,
      category,
      plannedAmount: plannedAmount || 0,
      actualAmount: actualAmount || 0,
    })

    // Populate the workspace reference before returning
    await newCost.populate("executionWorkspaceId", "stage")

    console.log("✅ Cost created successfully:", newCost._id)

    return NextResponse.json(newCost, { status: 201 })
  } catch (error) {
    console.error("❌ Error creating cost:", error)

    let errorMessage = "Failed to create cost"
    let statusCode = 500

    if (error instanceof mongoose.Error.ValidationError) {
      errorMessage = "Validation error: " + Object.values(error.errors).map((e: any) => e.message).join(", ")
      statusCode = 400
    } else if (error instanceof mongoose.Error.CastError) {
      errorMessage = "Invalid ID format"
      statusCode = 400
    } else if (error instanceof Error) {
      errorMessage = error.message
    }

    return NextResponse.json(
      { 
        message: errorMessage,
        error: process.env.NODE_ENV === "development" ? error : undefined
      },
      { status: statusCode }
    )
  }
}

/**
 * GET /api/execution/costs
 * Fetch all costs with optional filters
 */
export async function GET(req: NextRequest) {
  try {
    await connectDB()

    const { searchParams } = new URL(req.url)
    const executionWorkspaceId = searchParams.get("executionWorkspaceId")
    const category = searchParams.get("category")
    const approvalStatus = searchParams.get("approvalStatus")

    const filter: any = {}

    if (executionWorkspaceId) {
      filter.executionWorkspaceId = executionWorkspaceId
    }

    if (category) {
      filter.category = { $regex: category, $options: "i" }
    }

    if (approvalStatus) {
      filter.approvalStatus = approvalStatus
    }

    const costs = await Cost.find(filter)
      .sort({ createdAt: -1 })
      .populate("executionWorkspaceId", "stage")
      .lean()

    return NextResponse.json(costs, { status: 200 })
  } catch (error) {
    console.error("❌ Error fetching costs:", error)
    return NextResponse.json(
      { message: "Failed to fetch costs" },
      { status: 500 }
    )
  }
}